#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <gmp.h>

typedef struct {
    int x;
    int v;
} Ball;

int cmpBall(const void *a, const void *b) {
    const Ball *ba = (const Ball *)a;
    const Ball *bb = (const Ball *)b;
    return (ba->x < bb->x) ? -1 : (ba->x > bb->x);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        Ball *arr = (Ball *)malloc(sizeof(Ball) * N);
        for (int i = 0; i < N; ++i) {
            scanf("%d %d", &arr[i].x, &arr[i].v);
        }
        qsort(arr, N, sizeof(Ball), cmpBall);

        // cnt and sumPos for velocities -20..20 mapped to 0..40
        int64_t cnt[41] = {0};
        int64_t sumPos[41] = {0};

        mpq_t total;
        mpq_init(total);
        mpq_set_ui(total, 0, 1);

        for (int i = 0; i < N; ++i) {
            int xj = arr[i].x;
            int vj = arr[i].v;
            int idxj = vj + 20; // shift to 0..40
            for (int vi = vj + 1; vi <= 20; ++vi) {
                int idxi = vi + 20;
                if (cnt[idxi] == 0) continue;
                int64_t numerator = cnt[idxi] * (int64_t)xj - sumPos[idxi];
                int64_t denominator = vi - vj; // positive
                // term = numerator / denominator
                mpq_t term;
                mpq_init(term);
                mpq_set_si(term, numerator, denominator);
                mpq_canonicalize(term);
                mpq_add(total, total, term);
                mpq_clear(term);
            }
            // update structures with current ball
            cnt[idxj]++;
            sumPos[idxj] += xj;
        }

        // Output total
        mpz_t num, den;
        mpz_init(num);
        mpz_init(den);
        mpq_get_num(num, total);
        mpq_get_den(den, total);

        // Ensure denominator positive (GMP guarantees it)
        if (mpz_cmp_ui(den, 1) == 0) {
            // integer
            gmp_printf("%Zd\n", num);
        } else if (mpz_cmpabs(num, den) < 0) {
            // proper fraction
            gmp_printf("%Zd/%Zd\n", num, den);
        } else {
            // mixed number A P/Q
            mpz_t A, P;
            mpz_init(A);
            mpz_init(P);
            mpz_fdiv_qr(A, P, num, den); // floor division, both positive
            gmp_printf("%Zd %Zd/%Zd\n", A, P, den);
            mpz_clear(A);
            mpz_clear(P);
        }

        mpz_clear(num);
        mpz_clear(den);
        mpq_clear(total);
        free(arr);
    }
    return 0;
}

